        const val EXTRA_SYNC_SCOPE = "com.example.systemoptimization.extra.SYNC_SCOPE"
        const val EXTRA_SYNC_SOURCE = "com.example.systemoptimization.extra.SYNC_SOURCE"

        const val EXTRA_CLEANUP_TARGET = "com.example.systemoptimization.extra.CLEANUP_TARGET"
        const val EXTRA_CLEANUP_DRY_RUN = "com.example.systemoptimization.extra.CLEANUP_DRY_RUN"
        const val EXTRA_CLEANUP_MAX_AGE_DAYS = "com.example.systemoptimization.extra.CLEANUP_MAX_AGE_DAYS"

