class DataSyncManager(private val context: Context) {

    fun runSync(full: Boolean, scope: String?, source: String?, requestId: String?) {
        if (full) {
            syncAll(scope, source, requestId)
        } else {
            syncIncremental(scope, source, requestId)
        }
    }

    private fun syncAll(scope: String?, source: String?, requestId: String?) {
        Thread.sleep(300)
        persistSyncMarker("full", scope, source, requestId)
    }

    private fun syncIncremental(scope: String?, source: String?, requestId: String?) {
        Thread.sleep(150)
        persistSyncMarker("incremental", scope, source, requestId)
    }

    private fun persistSyncMarker(mode: String, scope: String?, source: String?, requestId: String?) {
        val prefs = context.getSharedPreferences("maintenance_tasks", Context.MODE_PRIVATE)
        prefs.edit()
            .putLong("last_sync_at", System.currentTimeMillis())
            .putString("last_sync_mode", mode)
            .putString("last_sync_scope", scope)
            .putString("last_sync_source", source)
            .putString("last_sync_request_id", requestId)
            .apply()
    }
}

class CleanupManager(private val context: Context) {

    fun runCleanup(target: String?, dryRun: Boolean, maxAgeDays: Int, requestId: String?) {
        val prefs = context.getSharedPreferences("maintenance_tasks", Context.MODE_PRIVATE)
        val editor = prefs.edit()

        val now = System.currentTimeMillis()
        val cutoffMs = now - maxAgeDays.toLong() * 24L * 60L * 60L * 1000L

        val deletedCount = performCleanup(target, cutoffMs, dryRun)

        editor
            .putLong("last_cleanup_at", now)
            .putString("last_cleanup_target", target)
            .putBoolean("last_cleanup_dry_run", dryRun)
            .putInt("last_cleanup_max_age_days", maxAgeDays)
            .putString("last_cleanup_request_id", requestId)
            .putInt("last_cleanup_deleted_count", deletedCount)
            .apply()
    }

    private fun performCleanup(target: String?, cutoffMs: Long, dryRun: Boolean): Int {
        Thread.sleep(200)
        if (dryRun) return 0
        return if (target.isNullOrBlank()) 5 else 2
    }
}